create or replace function private.create_business_asset_depreciation_run_internal(p_business_id uuid,p_period_start date,p_posting_date date,p_branch_id uuid default null,p_notes text default null) returns jsonb language plpgsql security definer set search_path=pg_catalog,public,private as $$ declare actor_id uuid:=auth.uid();run_record public.business_asset_depreciation_runs%rowtype;v_period_start date:=date_trunc('month',p_period_start)::date;v_period_end date:=(date_trunc('month',p_period_start)+interval '1 month - 1 day')::date; begin if actor_id is null or not private.can_depreciate_business_assets(p_business_id) then raise exception 'Asset depreciation permission required.' using errcode='42501';end if; perform private.validate_business_asset_branch(p_business_id,p_branch_id,actor_id,true); perform set_config('app.business_asset_action','run_write',true); insert into public.business_asset_depreciation_runs(business_id,branch_id,period_start,period_end,posting_date,notes,created_by) values(p_business_id,p_branch_id,v_period_start,v_period_end,p_posting_date,nullif(btrim(coalesce(p_notes,'')),''),actor_id) returning*into run_record; perform private.write_business_asset_audit(p_business_id,null,run_record.id,'depreciation_run_created',jsonb_build_object('period_start',run_record.period_start,'period_end',run_record.period_end,'branch_id',run_record.branch_id)); return to_jsonb(run_record)||jsonb_build_object('run_code','DEP-'||lpad(run_record.run_no::text,8,'0')); exception when unique_violation then raise exception 'A depreciation run already exists for this branch and month.' using errcode='23505'; end;$$;

create or replace function private.recalculate_business_asset_depreciation_run_internal(p_business_id uuid,p_run_id uuid) returns jsonb language plpgsql security definer set search_path=pg_catalog,public,private as $$ declare actor_id uuid:=auth.uid();run_record public.business_asset_depreciation_runs%rowtype;asset_record record;monthly_amount numeric(24,4);remaining_amount numeric(24,4);expected_period date;v_count integer;v_total numeric(24,4); begin if actor_id is null or not private.can_depreciate_business_assets(p_business_id) then raise exception 'Asset depreciation permission required.' using errcode='42501';end if; select*into run_record from public.business_asset_depreciation_runs where business_id=p_business_id and id=p_run_id for update; if not found then raise exception 'Depreciation run not found.' using errcode='P0002';end if; if run_record.status<>'draft' then raise exception 'Only draft depreciation runs can be recalculated.' using errcode='55000';end if; perform private.validate_business_asset_branch(p_business_id,run_record.branch_id,actor_id,true); perform set_config('app.business_asset_action','line_write',true); delete from public.business_asset_depreciation_lines where business_id=p_business_id and depreciation_run_id=p_run_id; for asset_record in select asset.*,category.depreciation_expense_account_id,category.accumulated_depreciation_account_id from public.business_fixed_assets asset join public.business_asset_categories category on category.business_id=asset.business_id and category.id=asset.category_id where asset.business_id=p_business_id and asset.status in ('active','fully_depreciated') and asset.book_value>asset.residual_value and (run_record.branch_id is null or asset.branch_id=run_record.branch_id) and (asset.branch_id is null or private.has_business_branch_access(p_business_id,asset.branch_id,actor_id)) order by asset.asset_code loop expected_period:=case when asset_record.last_depreciation_period_end is not null then (date_trunc('month',asset_record.last_depreciation_period_end)+interval '1 month')::date when asset_record.depreciation_convention='next_month' then (date_trunc('month',asset_record.in_service_date)+interval '1 month')::date else date_trunc('month',asset_record.in_service_date)::date end; if expected_period<>run_record.period_start then continue;end if; monthly_amount:=round((asset_record.original_cost-asset_record.residual_value)/asset_record.useful_life_months,4); remaining_amount:=asset_record.book_value-asset_record.residual_value; monthly_amount:=least(monthly_amount,remaining_amount); if monthly_amount<=0 then continue;end if; perform set_config('app.business_asset_action','line_write',true); insert into public.business_asset_depreciation_lines(business_id,depreciation_run_id,asset_id,expense_account_id,accumulated_depreciation_account_id,opening_accumulated_depreciation,depreciation_amount,closing_accumulated_depreciation,closing_book_value) values(p_business_id,p_run_id,asset_record.id,asset_record.depreciation_expense_account_id,asset_record.accumulated_depreciation_account_id,asset_record.accumulated_depreciation,monthly_amount,asset_record.accumulated_depreciation+monthly_amount,asset_record.book_value-monthly_amount); end loop; select count(*)::integer,coalesce(sum(depreciation_amount),0) into v_count,v_total from public.business_asset_depreciation_lines where business_id=p_business_id and depreciation_run_id=p_run_id; perform set_config('app.business_asset_action','run_write',true); update public.business_asset_depreciation_runs set asset_count=v_count,total_depreciation=v_total where business_id=p_business_id and id=p_run_id returning*into run_record; perform private.write_business_asset_audit(p_business_id,null,p_run_id,'depreciation_run_recalculated',jsonb_build_object('asset_count',run_record.asset_count,'total_depreciation',run_record.total_depreciation)); return to_jsonb(run_record)||jsonb_build_object('run_code','DEP-'||lpad(run_record.run_no::text,8,'0')); end;$$;

create or replace function private.post_business_asset_depreciation_run_internal(p_business_id uuid,p_run_id uuid) returns jsonb language plpgsql security definer set search_path=pg_catalog,public,private as $$ declare actor_id uuid:=auth.uid();run_record public.business_asset_depreciation_runs%rowtype;journal_id uuid;lines_json jsonb; begin if actor_id is null or not private.can_depreciate_business_assets(p_business_id) then raise exception 'Asset depreciation permission required.' using errcode='42501';end if; select*into run_record from public.business_asset_depreciation_runs where business_id=p_business_id and id=p_run_id for update; if not found then raise exception 'Depreciation run not found.' using errcode='P0002';end if; if run_record.status<>'draft' then raise exception 'Only draft depreciation runs can be posted.' using errcode='55000';end if; if run_record.asset_count<=0 or run_record.total_depreciation<=0 then raise exception 'Recalculate at least one eligible asset before posting.' using errcode='22023';end if; perform private.validate_business_asset_branch(p_business_id,run_record.branch_id,actor_id,true); select coalesce(jsonb_agg(line order by sort_key,account_id),'[]'::jsonb) into lines_json from (select 1 sort_key,expense_account_id account_id,jsonb_build_object('account_id',expense_account_id,'debit',sum(depreciation_amount),'credit',0,'description','Depreciation expense') line from public.business_asset_depreciation_lines where business_id=p_business_id and depreciation_run_id=p_run_id group by expense_account_id union all select 2 sort_key,accumulated_depreciation_account_id account_id,jsonb_build_object('account_id',accumulated_depreciation_account_id,'debit',0,'credit',sum(depreciation_amount),'description','Accumulated depreciation') line from public.business_asset_depreciation_lines where business_id=p_business_id and depreciation_run_id=p_run_id group by accumulated_depreciation_account_id) grouped; journal_id:=private.post_business_asset_journal_internal(p_business_id,p_run_id,run_record.posting_date,'asset_depreciation','DEP-'||lpad(run_record.run_no::text,8,'0'),'Fixed asset depreciation for '||to_char(run_record.period_start,'Mon YYYY'),lines_json); perform set_config('app.business_asset_action','asset_write',true); update public.business_fixed_assets asset set accumulated_depreciation=line.closing_accumulated_depreciation,book_value=line.closing_book_value,last_depreciation_period_end=run_record.period_end,status=case when line.closing_book_value<=asset.residual_value then 'fully_depreciated' else 'active' end,updated_by=actor_id from public.business_asset_depreciation_lines line where line.business_id=p_business_id and line.depreciation_run_id=p_run_id and asset.business_id=p_business_id and asset.id=line.asset_id; perform set_config('app.business_asset_action','run_write',true); update public.business_asset_depreciation_runs set status='posted',journal_entry_id=journal_id,posted_by=actor_id,posted_at=now() where business_id=p_business_id and id=p_run_id returning*into run_record; perform private.write_business_asset_audit(p_business_id,null,p_run_id,'depreciation_run_posted',jsonb_build_object('journal_entry_id',journal_id,'total_depreciation',run_record.total_depreciation)); return to_jsonb(run_record)||jsonb_build_object('run_code','DEP-'||lpad(run_record.run_no::text,8,'0')); end;$$;

create or replace function private.cancel_business_asset_depreciation_run_internal(p_business_id uuid,p_run_id uuid,p_reason text default null) returns jsonb language plpgsql security definer set search_path=pg_catalog,public,private as $$ declare actor_id uuid:=auth.uid();run_record public.business_asset_depreciation_runs%rowtype; begin if actor_id is null or not private.can_depreciate_business_assets(p_business_id) then raise exception 'Asset depreciation permission required.' using errcode='42501';end if; select*into run_record from public.business_asset_depreciation_runs where business_id=p_business_id and id=p_run_id for update; if not found then raise exception 'Depreciation run not found.' using errcode='P0002';end if; if run_record.status<>'draft' then raise exception 'Only draft depreciation runs can be cancelled.' using errcode='55000';end if; perform private.validate_business_asset_branch(p_business_id,run_record.branch_id,actor_id,true); perform set_config('app.business_asset_action','line_write',true); delete from public.business_asset_depreciation_lines where business_id=p_business_id and depreciation_run_id=p_run_id; perform set_config('app.business_asset_action','run_write',true); update public.business_asset_depreciation_runs set status='cancelled',asset_count=0,total_depreciation=0,cancelled_by=actor_id,cancelled_at=now() where business_id=p_business_id and id=p_run_id returning*into run_record; perform private.write_business_asset_audit(p_business_id,null,p_run_id,'depreciation_run_cancelled',jsonb_build_object('reason',nullif(btrim(coalesce(p_reason,'')),''))); return to_jsonb(run_record)||jsonb_build_object('run_code','DEP-'||lpad(run_record.run_no::text,8,'0')); end;$$;

create or replace function private.dispose_business_fixed_asset_internal(p_business_id uuid,p_asset_id uuid,p_disposal_date date,p_proceeds numeric,p_disposal_account_id uuid,p_reference text default null,p_write_off boolean default false) returns jsonb language plpgsql security definer set search_path=pg_catalog,public,private as $$ declare actor_id uuid:=auth.uid();asset_record public.business_fixed_assets%rowtype;category_record public.business_asset_categories%rowtype;settings_record public.business_asset_settings%rowtype;gain_amount numeric(24,4);loss_amount numeric(24,4);journal_id uuid;lines_json jsonb; begin if actor_id is null or not private.can_dispose_business_assets(p_business_id) then raise exception 'Fixed asset disposal permission required.' using errcode='42501';end if; select*into asset_record from public.business_fixed_assets where business_id=p_business_id and id=p_asset_id for update; if not found then raise exception 'Fixed asset not found.' using errcode='P0002';end if; if asset_record.status not in ('active','fully_depreciated') then raise exception 'Only active or fully depreciated assets can be disposed.' using errcode='55000';end if; perform private.validate_business_asset_branch(p_business_id,asset_record.branch_id,actor_id,true); if p_disposal_date<asset_record.in_service_date then raise exception 'Disposal date cannot be before the in-service date.' using errcode='22008';end if; if asset_record.last_depreciation_period_end is not null and p_disposal_date<=asset_record.last_depreciation_period_end then raise exception 'Disposal date must be after the latest depreciation period.' using errcode='22008';end if; if coalesce(p_proceeds,0)<0 then raise exception 'Disposal proceeds cannot be negative.' using errcode='22023';end if; if coalesce(p_write_off,false) and coalesce(p_proceeds,0)<>0 then raise exception 'A write-off cannot include disposal proceeds.' using errcode='22023';end if; if not coalesce(p_write_off,false) then if p_disposal_account_id is null or not exists(select 1 from public.business_chart_of_accounts where business_id=p_business_id and id=p_disposal_account_id and is_active and account_type='asset' and normal_balance='debit') then raise exception 'Select an active debit-balance asset account for disposal proceeds.' using errcode='23514'; end if; end if; category_record:=private.validate_business_asset_category_accounts(p_business_id,asset_record.category_id); select*into settings_record from public.business_asset_settings where business_id=p_business_id; gain_amount:=greatest(coalesce(p_proceeds,0)-asset_record.book_value,0); loss_amount:=greatest(asset_record.book_value-coalesce(p_proceeds,0),0); lines_json:='[]'::jsonb; if asset_record.accumulated_depreciation>0 then lines_json:=lines_json||jsonb_build_array(jsonb_build_object('account_id',category_record.accumulated_depreciation_account_id,'debit',asset_record.accumulated_depreciation,'credit',0,'description','Remove accumulated depreciation')); end if; if coalesce(p_proceeds,0)>0 then lines_json:=lines_json||jsonb_build_array(jsonb_build_object('account_id',p_disposal_account_id,'debit',p_proceeds,'credit',0,'description','Asset disposal proceeds')); end if; if loss_amount>0 then lines_json:=lines_json||jsonb_build_array(jsonb_build_object('account_id',settings_record.loss_on_disposal_account_id,'debit',loss_amount,'credit',0,'description','Loss on asset disposal')); end if; lines_json:=lines_json||jsonb_build_array(jsonb_build_object('account_id',category_record.asset_account_id,'debit',0,'credit',asset_record.original_cost,'description','Remove fixed asset cost')); if gain_amount>0 then lines_json:=lines_json||jsonb_build_array(jsonb_build_object('account_id',settings_record.gain_on_disposal_account_id,'debit',0,'credit',gain_amount,'description','Gain on asset disposal')); end if; journal_id:=private.post_business_asset_journal_internal(p_business_id,p_asset_id,p_disposal_date,'asset_disposal',p_reference,case when coalesce(p_write_off,false) then 'Write off ' else 'Dispose ' end||asset_record.name,lines_json); perform set_config('app.business_asset_action','asset_write',true); update public.business_fixed_assets set status=case when coalesce(p_write_off,false) then 'written_off' else 'disposed' end,disposal_date=p_disposal_date,disposal_proceeds=coalesce(p_proceeds,0),disposal_account_id=case when coalesce(p_write_off,false) then null else p_disposal_account_id end,disposal_journal_entry_id=journal_id,disposal_gain=gain_amount,disposal_loss=loss_amount,disposed_by=actor_id,disposed_at=now(),updated_by=actor_id where business_id=p_business_id and id=p_asset_id returning*into asset_record; perform private.write_business_asset_audit(p_business_id,p_asset_id,null,case when coalesce(p_write_off,false) then 'fixed_asset_written_off' else 'fixed_asset_disposed' end,jsonb_build_object('journal_entry_id',journal_id,'proceeds',coalesce(p_proceeds,0),'gain',gain_amount,'loss',loss_amount)); return to_jsonb(asset_record)||jsonb_build_object('asset_display_code','AST-'||lpad(asset_record.asset_no::text,8,'0')); end;$$;

create or replace function private.cancel_draft_business_fixed_asset_internal(p_business_id uuid,p_asset_id uuid,p_reason text default null) returns jsonb language plpgsql security definer set search_path=pg_catalog,public,private as $$ declare actor_id uuid:=auth.uid();asset_record public.business_fixed_assets%rowtype; begin if actor_id is null or not private.can_manage_business_assets(p_business_id) then raise exception 'Fixed asset management permission required.' using errcode='42501';end if; select*into asset_record from public.business_fixed_assets where business_id=p_business_id and id=p_asset_id for update; if not found then raise exception 'Fixed asset not found.' using errcode='P0002';end if; if asset_record.status<>'draft' then raise exception 'Only draft fixed assets can be cancelled.' using errcode='55000';end if; perform private.validate_business_asset_branch(p_business_id,asset_record.branch_id,actor_id,true); perform set_config('app.business_asset_action','asset_write',true); update public.business_fixed_assets set status='cancelled',updated_by=actor_id where business_id=p_business_id and id=p_asset_id returning*into asset_record; perform private.write_business_asset_audit(p_business_id,p_asset_id,null,'fixed_asset_cancelled',jsonb_build_object('reason',nullif(btrim(coalesce(p_reason,'')),''))); return to_jsonb(asset_record)||jsonb_build_object('asset_display_code','AST-'||lpad(asset_record.asset_no::text,8,'0')); end;$$;
